/**
 * Property Panel Component
 * Edits selected room properties
 */

import React, { useState, useEffect } from 'react';
import useWorldBuilderStore from '../store/store.js';

function PropertyPanel() {
  const { currentAreaData, selectedRoom, updateRoom, deleteRoom, addExit, removeExit, loading } =
    useWorldBuilderStore();

  const [formData, setFormData] = useState({
    name: '',
    desc: '',
    flags: [],
    type: 'normal',
    terrain: 'any',
  });

  const [newExit, setNewExit] = useState({
    direction: 'north',
    targetVnum: '',
    doorType: 'none',
  });

  const room = currentAreaData?.rooms.find((r) => r.vnum === selectedRoom);

  useEffect(() => {
    if (room) {
      setFormData({
        name: room.name,
        desc: room.desc,
        flags: room.flags || [],
        type: room.type || 'normal',
        terrain: room.terrain || 'any',
      });
    }
  }, [room]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSaveRoom = () => {
    if (room) {
      updateRoom(room.vnum, formData);
    }
  };

  const handleDeleteRoom = () => {
    if (room && window.confirm(`Delete room ${room.vnum}? This cannot be undone.`)) {
      deleteRoom(room.vnum);
    }
  };

  const handleAddExit = () => {
    if (room && newExit.targetVnum) {
      addExit(room.vnum, {
        direction: newExit.direction,
        targetVnum: parseInt(newExit.targetVnum),
        doorType: newExit.doorType,
      });
      setNewExit({ direction: 'north', targetVnum: '', doorType: 'none' });
    }
  };

  const handleRemoveExit = (direction) => {
    if (room) {
      removeExit(room.vnum, direction);
    }
  };

  if (!room) {
    return (
      <div className="property-panel">
        <h2>⚙️ Properties</h2>
        <p className="text-muted mt-2">Select a room to edit its properties</p>
      </div>
    );
  }

  const directionOptions = ['north', 'south', 'east', 'west', 'up', 'down'];
  const roomVnums = currentAreaData?.rooms.map((r) => r.vnum) || [];

  return (
    <div className="property-panel">
      <h2>⚙️ Properties</h2>
      <div className="property-content">
        {/* Room Info */}
        <div className="card">
          <div className="card-header">Room {room.vnum}</div>
          <div className="grid mt-2">
            <input
              type="text"
              name="name"
              placeholder="Room Name"
              value={formData.name}
              onChange={handleInputChange}
              className="mb-2"
            />
            <select
              name="type"
              value={formData.type}
              onChange={handleInputChange}
              className="mb-2"
            >
              <option value="normal">Normal</option>
              <option value="dark">Dark</option>
              <option value="safe">Safe</option>
              <option value="shop">Shop</option>
              <option value="temple">Temple</option>
            </select>
          </div>

          <label htmlFor="desc" className="form-label">
            Description
          </label>
          <textarea
            name="desc"
            placeholder="Room description..."
            value={formData.desc}
            onChange={handleInputChange}
            rows="5"
            className="mb-2"
            style={{ fontFamily: 'monospace' }}
          />

          <div className="button-group">
            <button onClick={handleSaveRoom} disabled={loading}>
              💾 Save
            </button>
            <button onClick={handleDeleteRoom} disabled={loading} className="danger">
              🗑️ Delete
            </button>
          </div>
        </div>

        {/* Exits */}
        <div className="card">
          <div className="card-header">Exits ({room.exits?.length || 0})</div>

          {room.exits && room.exits.length > 0 ? (
            <div className="exits-list">
              {room.exits.map((exit) => (
                <div key={exit.direction} className="exit-item">
                  <div className="exit-info">
                    <strong>{exit.direction}</strong> → Room {exit.targetVnum}
                  </div>
                  <button
                    onClick={() => handleRemoveExit(exit.direction)}
                    disabled={loading}
                    className="danger"
                    style={{ padding: '4px 8px', fontSize: '12px' }}
                  >
                    Remove
                  </button>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-muted mt-2">No exits. Add one below.</p>
          )}

          <div className="add-exit mt-2" style={{ borderTop: '1px solid #eee', paddingTop: '12px' }}>
            <h4 style={{ fontSize: '13px', marginBottom: '8px' }}>Add Exit</h4>
            <div className="grid mb-2" style={{ gridTemplateColumns: '1fr 1fr' }}>
              <select
                value={newExit.direction}
                onChange={(e) => setNewExit({ ...newExit, direction: e.target.value })}
              >
                {directionOptions.map((dir) => (
                  <option key={dir} value={dir}>
                    {dir.charAt(0).toUpperCase() + dir.slice(1)}
                  </option>
                ))}
              </select>
              <select
                value={newExit.targetVnum}
                onChange={(e) => setNewExit({ ...newExit, targetVnum: e.target.value })}
              >
                <option value="">Select Room...</option>
                {roomVnums
                  .filter((vnum) => vnum !== room.vnum)
                  .map((vnum) => (
                    <option key={vnum} value={vnum}>
                      {vnum}
                    </option>
                  ))}
              </select>
            </div>
            <button onClick={handleAddExit} disabled={loading || !newExit.targetVnum}>
              ➕ Add Exit
            </button>
          </div>
        </div>
      </div>

      <style>{`
        .property-panel {
          display: flex;
          flex-direction: column;
          height: 100%;
        }

        .property-panel h2 {
          font-size: 18px;
          margin-bottom: 16px;
        }

        .property-content {
          flex: 1;
          overflow-y: auto;
        }

        .card {
          background: white;
          border: 1px solid #ddd;
          border-radius: 8px;
          padding: 16px;
          margin-bottom: 16px;
        }

        .form-label {
          display: block;
          font-weight: bold;
          font-size: 13px;
          margin-bottom: 4px;
        }

        .button-group {
          display: flex;
          gap: 8px;
        }

        .button-group button {
          flex: 1;
        }

        .exits-list {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .exit-item {
          background: #f9f9f9;
          border: 1px solid #eee;
          border-radius: 4px;
          padding: 8px;
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .exit-info {
          font-size: 13px;
        }
      `}</style>
    </div>
  );
}

export default PropertyPanel;
